var claudeRaw = $('Call Claude AI').first().json;
var brief = $('Build Claude Prompt').first().json;

var content = '';
try {
  if (claudeRaw.content && Array.isArray(claudeRaw.content)) {
    content = claudeRaw.content.map(function(b){ return b.text || ''; }).join('\n');
  } else if (claudeRaw.text) {
    content = claudeRaw.text;
  } else {
    content = JSON.stringify(claudeRaw);
  }
} catch(e) {
  content = 'Error extracting content: ' + e.message;
}

var metaTitle = '';
var metaDesc = '';
var seoScore = 0;

try {
  var mtMatch = content.match(/META_TITLE:\s*(.+)/);
  if (mtMatch) metaTitle = mtMatch[1].trim();
  var mdMatch = content.match(/META_DESC:\s*(.+)/);
  if (mdMatch) metaDesc = mdMatch[1].trim();
  var ssMatch = content.match(/SEO_SCORE:\s*(\d+)/);
  if (ssMatch) seoScore = parseInt(ssMatch[1]);
} catch(e) {}

if (!metaTitle) metaTitle = brief.topic;
if (!metaDesc) metaDesc = 'Read our guide on ' + brief.topic;
if (!seoScore) seoScore = 72;

var slug = (brief.keyword || brief.topic).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');

var valueMap = { blog_post: 250, ad_copy: 150, email_sequence: 350, social_captions: 120 };

return [{ json: {
  jobId: brief.jobId,
  contentType: brief.contentType,
  topic: brief.topic,
  keyword: brief.keyword,
  brand: brief.brand,
  clientEmail: brief.clientEmail,
  sendgridKey: brief.sendgridKey,
  generatedContent: content,
  contentLength: content.length,
  metaTitle: metaTitle,
  metaDesc: metaDesc,
  seoScore: seoScore,
  slug: slug,
  estimatedValue: valueMap[brief.contentType] || 200,
  generatedAt: new Date().toISOString()
}}];
